// src/components/common/Navbar.js
import React, { useState, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { Menu, X, Code, Globe } from 'lucide-react';

function Navbar({ lang, setLang, t }) {
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);
  const [projectCode, setProjectCode] = useState('');
  const location = useLocation();

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 50);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const handleProjectCodeSubmit = (e) => {
    e.preventDefault();
    if (projectCode.trim()) {
      window.location.href = `/track/${projectCode.trim().toUpperCase()}`;
    }
  };

  const navItems = [
    { path: '/', label: t.nav.services, isHome: true },
    { path: '/portfolio', label: t.nav.portfolio },
    { path: '/pricing', label: t.nav.pricing },
    { path: '/faq', label: t.nav.faq },
    { path: '/contact', label: t.nav.contact }
  ];

  const isActive = (path) => {
    if (path === '/' && location.pathname === '/') return true;
    if (path !== '/' && location.pathname === path) return true;
    return false;
  };

  return (
    <nav className={`fixed top-0 w-full z-50 border-b transition-all duration-300 ${
      scrolled 
        ? 'bg-white/95 backdrop-blur-md border-gray-200 shadow-lg' 
        : 'bg-white/80 backdrop-blur-sm border-gray-100'
    }`}>
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between items-center h-16">
          {/* Logo */}
          <Link to="/" className="flex items-center space-x-2">
            <Code className="w-8 h-8 text-emerald-500" />
            <span className="text-xl font-bold text-gray-900">DevStudio</span>
          </Link>

          {/* Desktop Menu */}
          <div className="hidden md:flex items-center space-x-8">
            {navItems.map((item) => (
              <Link
                key={item.path}
                to={item.path}
                className={`transition font-medium ${
                  isActive(item.path)
                    ? 'text-emerald-600'
                    : 'text-gray-600 hover:text-emerald-600'
                }`}
              >
                {item.label}
              </Link>
            ))}

            {/* Language Switch */}
            <button 
              onClick={() => setLang(lang === 'vi' ? 'en' : 'vi')}
              className="flex items-center space-x-1 text-gray-600 hover:text-emerald-600 transition font-medium"
            >
              <Globe className="w-5 h-5" />
              <span>{lang === 'vi' ? 'EN' : 'VI'}</span>
            </button>
          </div>

          {/* Mobile Menu Button */}
          <button 
            className="md:hidden text-gray-700"
            onClick={() => setIsMenuOpen(!isMenuOpen)}
          >
            {isMenuOpen ? <X /> : <Menu />}
          </button>
        </div>
      </div>

      {/* Project Tracker Bar */}
      <div className="w-full border-t border-gray-100 bg-gray-50 py-4 px-4">
        <div className="max-w-7xl mx-auto flex flex-col sm:flex-row items-center justify-center gap-4">
          <span className="text-gray-700 text-base font-semibold whitespace-nowrap flex items-center gap-2">
            <span className="text-xl">📊</span>
            {t.hero.tracker.label}
          </span>
          <form onSubmit={handleProjectCodeSubmit} className="flex gap-3 w-full sm:w-auto">
            <input
              type="text"
              value={projectCode}
              onChange={(e) => setProjectCode(e.target.value)}
              placeholder={t.hero.tracker.placeholder}
              className="bg-white border-2 border-gray-200 text-gray-900 px-5 py-3 rounded-xl focus:outline-none focus:border-emerald-500 text-base flex-1 sm:w-72 placeholder:text-gray-400 shadow-sm"
            />
            <button
              type="submit"
              className="bg-emerald-500 hover:bg-emerald-600 text-white px-8 py-3 rounded-xl font-bold text-base whitespace-nowrap shadow-md hover:shadow-lg transition-all"
            >
              {t.hero.tracker.button}
            </button>
          </form>
        </div>
      </div>

      {/* Mobile Menu */}
      {isMenuOpen && (
        <div className="md:hidden bg-white border-t border-gray-100">
          {navItems.map((item) => (
            <Link
              key={item.path}
              to={item.path}
              onClick={() => setIsMenuOpen(false)}
              className={`block w-full text-left px-4 py-3 ${
                isActive(item.path)
                  ? 'text-emerald-600 bg-emerald-50'
                  : 'text-gray-700 hover:bg-gray-50 hover:text-emerald-600'
              }`}
            >
              {item.label}
            </Link>
          ))}
          <button 
            onClick={() => {
              setLang(lang === 'vi' ? 'en' : 'vi');
              setIsMenuOpen(false);
            }}
            className="block w-full text-left px-4 py-3 text-gray-700 hover:bg-gray-50 hover:text-emerald-600"
          >
            🌐 {lang === 'vi' ? 'English' : 'Tiếng Việt'}
          </button>
        </div>
      )}
    </nav>
  );
}

export default Navbar;
